using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver.
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ── 1. Strongly-typed retrieval: JsonTypeInfo<T> ──────────────────────
//    GetTypeInfo(Type) returns the non-generic JsonTypeInfo;
//    cast it to JsonTypeInfo<T> for the strongly-typed version.
JsonTypeInfo<Person> personInfo =
    (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));

Console.WriteLine($"Type handled : {personInfo.Type.Name}");
Console.WriteLine($"Kind         : {personInfo.Kind}");
Console.WriteLine($"Properties   : {personInfo.Properties.Count}");
Console.WriteLine();

// ── 2. Probe without throwing: TryGetTypeInfo ─────────────────────────
//    Returns false instead of throwing when metadata isn't available.
//    Here we use a resolver that knows about nothing, so it will return false.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new EmptyResolver()
};

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Found metadata for Person: {info!.Type.Name}");
}
else
{
    Console.WriteLine("No metadata for Person — and no exception was thrown.");
}

// Double-check: the full options *do* resolve it.
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2))
{
    var typed = (JsonTypeInfo<Person>)info2!;
    Console.WriteLine($"Full options resolved Person → Kind={typed.Kind}");
}

// ── Types ─────────────────────────────────────────────────────────────
record Person(string Name, int Age);

// A resolver that resolves nothing — used to demo the "not available" path.
sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

